class Solution:
    def strongPasswordChecker(self, password: str) -> int:
        n = len(password)
        missing = 3
        has_lower = has_upper = has_digit = False
        one = two = replace = 0
        for i, ch in enumerate(password):
            if ch.islower():
                has_lower = True
            elif ch.isupper():
                has_upper = True
            elif ch.isdigit():
                has_digit = True
            if i >= 2 and password[i] == password[i - 1] == password[i - 2]:
                if password[i] in '!?':
                    one += 1
                elif password[i].islower():
                    one += 1
                    replace += 1
                elif password[i].isupper():
                    two += 1
                    replace += 1
                else:
                    one += 1
                    two += 1
                    replace += 1
        if missing > n:
            return missing - (has_lower + has_upper + has_digit)
        res = 0
        if not has_lower:
            res += 1
        if not has_upper:
            res += 1
        if not has_digit:
            res += 1
        res += max(0, replace - (one + max(two, n - missing)))
        return res
